return items.map(item => {
  const data = item.json;
  const dias = Number(data.dias);

  let estado = "";
  let tipo_precio = "";
  let dias_validos = false;

  if (dias < 60) {
    estado = "invalido_minimo";
  } else if (dias > 365) {
    estado = "invalido_maximo";
  } else {
    dias_validos = true;

    if (dias < 180) {
      estado = "precio_corto";
      tipo_precio = "corto";
    } else {
      estado = "precio_normal";
      tipo_precio = "normal";
    }
  }

  return {
    json: {
      ...data,
      estado,
      tipo_precio,
      dias_validos
    }
  };
});

